export function eachNode(root, callback) {
    var node = root,
        current,
        next = [node],
        children,
        i,
        n;
    do {
        current = next;
        while ((node = current.pop())) {
            callback(node), (children = node.children);
            if (children) {
                for (i = children.length - 1; i >= 0; i--) {
                    current.push(children[i]);
                }
            }
        }
    } while (next.length);
}

export function eachNodeBeforeAfter(root, callbackBefore, callbackAfter) {
    var node = root,
        current,
        next = [node],
        children,
        i,
        n;
    do {
        current = next;
        while ((node = current.pop())) {
            callbackBefore(node), (children = node.children);
            if (children) {
                for (i = children.length - 1; i >= 0; i--) {
                    callbackAfter(node, children[i]);
                    current.push(children[i]);
                }
            }
        }
    } while (next.length);
}
